import json

problems = []

def add(year, num, topic, prob, choices, ans, source_link):
    diff = "easy" if num <= 8 else ("medium" if num <= 18 else "hard")
    idx = ord(ans) - ord('A')
    problems.append({
        "contest": "AMC 10B",
        "year": year,
        "number": num,
        "topic": topic,
        "difficulty": diff,
        "problem": prob,
        "choices": choices,
        "correct_answer": ans,
        "correct_value": choices[idx],
        "solution": "See AoPS wiki for detailed solution.",
        "track": "math",
        "source_link": source_link
    })

